output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?hostCountry ?winner ?hostCountryLabel ?winnerLabel WHERE {
  wd:Q284163 wdt:P17 ?hostCountry .
  wd:Q284163 wdt:P1346 ?winner .
  OPTIONAL {
    ?hostCountry rdfs:label ?hostCountryLabel .
    FILTER(LANG(?hostCountryLabel) = 'en')
  }
  OPTIONAL {
    ?winner rdfs:label ?winnerLabel .
    FILTER(LANG(?winnerLabel) = 'en')
  }
}

